186	                  'Contains operator is not allowed with `{{searchValue}}`. Use equals or more than operators instead.',
187	                  { searchValue }
188	                )
189	              );
190	              setIndicator(ValidatedOptions.error);
191	              return { ...result, hasError: true };
192	            } else if (v.includes(FilterCompare.notMatch)) {
193	              setCompare(FilterCompare.notMatch);
194	              result.comparator = FilterCompare.notMatch;
195	            } else {
196	              setCompare(FilterCompare.match);
197	              result.comparator = FilterCompare.match;
198	            }
199	          }
200	          // set direction
201	          if (def.category === 'source') {
202	            setDirection('source');
203	          } else if (def.category === 'destination') {
204	            setDirection('destination');
205	          } else {
206	            setDirection(undefined);
207	          }
208	          //set filter
209	          setFilter(def);
210	          result.def = def;
211	        } else if (submitOnRefresh) {
212	          setMessage(t("Can't find filter `{{searchValue}}`", { searchValue }));
213	          setIndicator(ValidatedOptions.error);
214	          return { ...result, hasError: true };
215	        }
216	        setValue(fieldValue[1]);
217	        result.value = fieldValue[1];
218	      } else if (fieldValue.length === 1) {
219	        // check if the value match a field
220	        const searchValue = v.toLowerCase();
221	        const def = filterDefinitions.find(def => def.id.toLowerCase() === searchValue);
222	        if (def) {
223	          // set direction
224	          if (def.category === 'source') {
225	            setDirection('source');
226	          } else if (def.category === 'destination') {
227	            setDirection('destination');
228	          } else {
229	            setDirection(undefined);
230	          }
231	          // set filter and reset the rest
232	          setFilter(def);
233	          setCompare(FilterCompare.match);
234	          setValue('');
235	          result.def = def;
236	        } else {
237	          // set simple value on current filter
238	          setValue(v);
239	          result.value = v;
240	        }
241	      } else {
242	        setMessage(t('Invalid format. The input should be <filter><comparator><value> such as `name=netobserv`.'));
243	        setIndicator(ValidatedOptions.error);
244	        return { ...result, hasError: true };
245	      }
246	
247	      if (submitOnRefresh) {
248	        setSubmitPending(true);
249	      }
250	
251	      return result;
252	    },
253	    // eslint-disable-next-line react-hooks/exhaustive-deps
254	    [compare, filterDefinitions, searchInputValue, setMessage]
255	  );
256	
257	  const getEncodedValue = React.useCallback(
258	    (v: string = value) => {
259	      return matcher(filter.id, [v], compare);
260	    },
261	    [compare, filter, value]
262	  );
263	
264	  const onToggle = React.useCallback(() => {
265	    setSuggestions([]);
266	    if (!isPopperOpen) {
267	      updateForm();
268	      setPopperOpen(true);
269	    }
270	  }, [isPopperOpen, updateForm]);
271	
272	  const onSearchChange = React.useCallback(
273	    (v: string) => {
274	      const defToSuggestion = (fd: FilterDefinition) => {
275	        return {
276	          display:
277	            fd.category === 'source'
278	              ? `${t('Source')} ${fd.name}`
279	              : fd.category === 'destination'
280	              ? `${t('Destination')} ${fd.name}`
281	              : fd.name,
282	          value: fd.id,
283	          validate: false,
284	          filterDef: fd
285	        };
286	      };
287	
288	      const optionToSuggestion = (o: FilterOption) => {
289	        return { display: o.name !== o.value ? o.name : undefined, value: o.value, validate: true };
290	      };
291	
292	      setSearchInputValue(v);
293	      const updated = updateForm(v);
294	      if (!v.length || updated.hasError) {
295	        setSuggestions([]);
296	        return;
297	      } else if (updated.def) {
298	        if (updated.comparator) {
299	          // suggest values if autocomplete and field set
300	          if (filter.component === 'autocomplete') {
301	            filter
302	              .autocomplete(updated.value || '')
303	              .then(v => {
304	                setSuggestions(v.map(optionToSuggestion));
305	              })
306	              .catch(err => {
307	                const errorMessage = getGenericHTTPError(err);
308	                setMessage(errorMessage);
309	                setSuggestions([]);
310	              });
311	          } else {
312	            // cleanup suggestions if values can't be guessed
313	            setSuggestions([]);
314	          }
315	        } else {
316	          // suggest comparators if field set but not value
317	          let suggestions = Object.values(FilterCompare).map(fc => {
318	            return { display: getCompareText(fc, t), value: fc, validate: false };
319	          }) as Suggestion[];
320	          if (filter.component === 'number') {
321	            suggestions = suggestions.filter(
322	              s => s.value !== FilterCompare.match && s.value !== FilterCompare.notMatch
323	            );
324	          } else {
325	            suggestions = suggestions.filter(s => s.value != FilterCompare.moreThanOrEqual);
326	          }
327	          // also suggest other definitions containing the id
328	          setSuggestions(
329	            suggestions.concat(
330	              filterDefinitions
331	                .filter(fd => fd.id !== updated.def!.id && fd.id.includes(updated.def!.id))
332	                .map(defToSuggestion)
333	            )
334	          );
335	        }
336	      } else if (updated.value?.length) {
337	        // suggest fields if def is not matched yet
338	        const suggestions = filterDefinitions
339	          .filter(fd => fd.id.includes(updated.value!))
340	          .map(defToSuggestion) as Suggestion[];
341	        if (filter.component === 'autocomplete') {
342	          filter
343	            .autocomplete(updated.value)
344	            .then(v => {
345	              setSuggestions(suggestions.concat(v.map(optionToSuggestion)));
346	            })
347	            .catch(err => {
348	              const errorMessage = getGenericHTTPError(err);
349	              setMessage(errorMessage);
350	              setSuggestions(suggestions);
351	            });
352	        } else {
353	          setSuggestions(suggestions);
354	        }
355	      }
356	    },
357	    // eslint-disable-next-line react-hooks/exhaustive-deps
358	    [filter, filterDefinitions, setMessage, setSearchInputValue, updateForm]
359	  );
360	
361	  const searchInput = React.useCallback(
362	    () => (
363	      <SearchInput
364	        onClear={reset}
365	        onKeyDown={e => {
366	          if (suggestions.length) {
367	            // focus on suggestions on tab / arrow down keys
368	            if (e.key === 'Tab' || e.key === 'ArrowDown') {
369	              e.preventDefault();
370	              document.getElementById('suggestion-0')?.focus();
371	            } else if (e.key === 'Escape') {
372	              // clear suggestions on esc key
373	              setSuggestions([]);
374	            }
375	          } else if (e.key === 'ArrowDown') {
376	            // get suggestions back
377	            onSearchChange(searchInputValue);
378	          }
379	        }}
380	        onChange={(e, v) => onSearchChange(v)}
381	        onSearch={(e, v) => {
382	          setSuggestions([]);
383	          if (_.isEmpty(v)) {
384	            setPopperOpen(true);
385	          } else {
386	            setSearchInputValue(v);
387	            updateForm(v, true);
388	          }
389	        }}
390	        onToggleAdvancedSearch={onToggle}
391	        value={isPopperOpen ? getEncodedValue() : searchInputValue}
392	        isAdvancedSearchOpen={isPopperOpen}
393	        placeholder={filter?.hint}
394	        ref={searchInputRef}
395	        id="filter-search-input"
396	      />
397	    ),
398	    [
399	      filter?.hint,
400	      getEncodedValue,
401	      isPopperOpen,
402	      onSearchChange,
403	      onToggle,
404	      reset,
405	      searchInputValue,
406	      setSearchInputValue,
407	      suggestions.length,
408	      updateForm
409	    ]
410	  );
411	
412	  const popper = React.useCallback(() => {
413	    return (
414	      <div id="filter-popper" ref={popperRef} role="dialog">
415	        {suggestions.length ? (
416	          <FilterSearchSuggestions
417	            suggestions={suggestions}
418	            setSuggestions={setSuggestions}
419	            searchInput={searchInputRef.current}
420	            searchInputValue={searchInputValue}
421	            updateForm={updateForm}
422	            onSearchChange={onSearchChange}
423	          />
424	        ) : (
425	          <FilterSearchPanel
426	            config={config}
427	            filterDefinitions={filterDefinitions}
428	            direction={direction}
429	            setDirection={setDirection}
430	            filter={filter}
431	            setFilter={setFilter}
432	            filters={filters}
433	            compare={compare}
434	            setCompare={setCompare}
435	            addFilter={addFilter}
436	            addFilterFromSuggestions={addFilterFromSuggestions}
437	            setMessage={setMessage}
438	            indicator={indicator}
439	            setIndicator={setIndicator}
440	            value={value}
441	            setValue={setValue}
442	            reset={reset}
443	          />
444	        )}
445	      </div>
446	    );
447	    // eslint-disable-next-line react-hooks/exhaustive-deps
448	  }, [
449	    popperRef,
450	    suggestions,
451	    filterDefinitions,
452	    direction,
453	    setDirection,
454	    filter,
455	    setFilter,
456	    compare,
457	    setCompare,
458	    addFilter,
459	    setMessage,
460	    indicator,
461	    setIndicator,
462	    value,
463	    setValue,
464	    reset,
465	    updateForm,
466	    searchInputValue,
467	    onSearchChange
468	  ]);
469	
470	  React.useEffect(() => {
471	    if (submitPending) {
472	      setSubmitPending(false);
473	      addFilterFromSuggestions();
474	    }
475	    // eslint-disable-next-line react-hooks/exhaustive-deps
476	  }, [submitPending, setSubmitPending, addFilter, value]);
477	
478	  return (
479	    <div id="filter-search-input-container" ref={filterSearchInputContainerRef}>
480	      <Popper
481	        trigger={searchInput()}
482	        triggerRef={searchInputRef}
483	        popper={popper()}
484	        popperRef={popperRef}
485	        isVisible={isPopperOpen || suggestions.length > 0}
486	        enableFlip={false}
487	        appendTo={filterSearchInputContainerRef.current || undefined}
488	      />
489	    </div>
490	  );
491	};
492	
493	export default FilterSearchInput;

