475	    // eslint-disable-next-line react-hooks/exhaustive-deps
476	  }, [submitPending, setSubmitPending, addFilter, value]);
477	
478	  return (
479	    <div id="filter-search-input-container" ref={filterSearchInputContainerRef}>
480	      <Popper
481	        trigger={searchInput()}
482	        triggerRef={searchInputRef}
483	        popper={popper()}
484	        popperRef={popperRef}
485	        isVisible={isPopperOpen || suggestions.length > 0}
486	      />
487	    </div>
488	  );
489	};
490	
491	export default FilterSearchInput;

