  1	import { Popper, SearchInput, ValidatedOptions } from '@patternfly/react-core';
  2	import _ from 'lodash';
  3	import * as React from 'react';
  4	import { useTranslation } from 'react-i18next';
  5	import { Config } from '../../../model/config';
  6	import {
  7	  createFilterValue,
  8	  FilterCompare,
  9	  FilterDefinition,
 10	  FilterOption,
 11	  Filters,
 12	  FilterValue,
 13	  findFromFilters,
 14	  getCompareText
 15	} from '../../../model/filters';
 16	import { getGenericHTTPError } from '../../../utils/errors';
 17	import { matcher, undefinedValue } from '../../../utils/filter-definitions';
 18	import { Indicator, setEndpointFilterDefinition } from '../../../utils/filters-helper';
 19	import { useOutsideClickEvent } from '../../../utils/outside-hook';
 20	import { Direction } from '../filters-toolbar';
 21	import './filter-search-input.css';
 22	import { FilterSearchPanel } from './filter-search-panel';
 23	import { FilterSearchSuggestions } from './filter-search-suggestions';
 24	
 25	export interface FormUpdateResult {
 26	  def?: FilterDefinition;
 27	  comparator?: FilterCompare;
 28	  value?: string;
 29	  hasError: boolean;
 30	}
 31	
 32	export interface Suggestion {
 33	  display?: string;
 34	  value: string;
 35	  validate?: boolean;
 36	  filterDef?: FilterDefinition;
 37	}
 38	
 39	export interface FilterSearchInputProps {
 40	  config: Config;
 41	  filterDefinitions: FilterDefinition[];
 42	  filters?: Filters;
 43	  searchInputValue: string;
 44	  indicator: Indicator;
 45	  direction: Direction;
 46	  filter: FilterDefinition;
 47	  compare: FilterCompare;
 48	  value: string;
 49	  setValue: (v: string) => void;
 50	  setCompare: (v: FilterCompare) => void;
 51	  setFilter: (v: FilterDefinition | null | undefined) => void;
 52	  setDirection: (v: Direction) => void;
 53	  setIndicator: (v: Indicator) => void;
 54	  setSearchInputValue: (v: string) => void;
 55	  setFilters: (v: Filters) => void;
 56	  setMessage: (m: string | undefined) => void;
 57	}
 58	
 59	export const FilterSearchInput: React.FC<FilterSearchInputProps> = ({
 60	  config,
 61	  filterDefinitions,
 62	  filters,
 63	  searchInputValue,
 64	  indicator,
 65	  direction,
 66	  filter,
 67	  compare,
 68	  value,
 69	  setValue,
 70	  setCompare,
 71	  setFilter,
 72	  setDirection,
 73	  setIndicator,
 74	  setSearchInputValue,
 75	  setFilters,
 76	  setMessage
 77	}) => {
 78	  const { t } = useTranslation('plugin__netobserv-plugin');
 79	
 80	  const filterSearchInputContainerRef = React.useRef(null);
 81	  const searchInputRef = React.useRef<HTMLInputElement>(null);
 82	  const popperRef = useOutsideClickEvent(() => {
 83	    // delay this to avoid conflict with onToggle event
 84	    // clicking on the arrow will skip the onToggle and trigger this code after the delay
 85	    setTimeout(() => {
 86	      if (suggestions.length) {
 87	        setSuggestions([]);
 88	      } else {
 89	        setPopperOpen(false);
 90	        setSearchInputValue(getEncodedValue());
 91	        // clear search field to show the placeholder back
 92	        if (_.isEmpty(value)) {
 93	          setSearchInputValue('');
 94	        }
 95	      }
 96	    }, 100);
 97	  });
 98	  const [suggestions, setSuggestions] = React.useState<Suggestion[]>([]);
 99	  const [isPopperOpen, setPopperOpen] = React.useState(false);
100	  const [submitPending, setSubmitPending] = React.useState(false);
101	
102	  const reset = React.useCallback(() => {
103	    setCompare(FilterCompare.equal);
104	    setValue('');
105	    setSearchInputValue('');
106	  }, [setCompare, setSearchInputValue, setValue]);
107	
108	  const addFilter = React.useCallback(
109	    (filterValue: FilterValue) => {
110	      const newFilters = _.cloneDeep(filters?.list) || [];
111	      let def = filter;
112	      // force bidirectional mode to have directions set
113	      if (filters?.match === 'bidirectional') {
114	        def = setEndpointFilterDefinition(filterDefinitions, def, direction === 'destination' ? 'dst' : 'src');
115	      }
116	      const found = findFromFilters(newFilters, { def, compare });
117	      if (found) {
118	        if (found.values.map(value => value.v).includes(filterValue.v)) {
119	          setMessage(t('Filter already exists'));
120	          setIndicator(ValidatedOptions.error);
121	          return false;
122	        } else {
123	          found.values.push(filterValue);
124	        }
125	      } else {
126	        newFilters.push({ def, compare, values: [filterValue] });
127	      }
128	
129	      setFilters({ ...filters!, list: newFilters });
130	      setPopperOpen(false);
131	      setSuggestions([]);
132	      reset();
133	      return true;
134	    },
135	    // eslint-disable-next-line react-hooks/exhaustive-deps
136	    [filter, filters, filterDefinitions, compare, setFilters, setMessage]
137	  );
138	
139	  const addFilterFromSuggestions = React.useCallback(
140	    () => {
141	      // Use createFilterValue to get proper display text via findOption
142	      // Convert empty strings to undefinedValue for proper "n/a" display
143	      const valueToUse = value === '' ? undefinedValue : value;
144	      const filterValue = createFilterValue(filter, valueToUse);
145	      addFilter(filterValue);
146	    },
147	    // eslint-disable-next-line react-hooks/exhaustive-deps
148	    [addFilter, filter, value]
149	  );
150	
151	  const updateForm = React.useCallback(
152	    (v: string = searchInputValue, submitOnRefresh?: boolean) => {
153	      // parse search input value to form content
154	      const fieldValue = v.split(/>=|!=|!~|=|~/);
155	      const result: FormUpdateResult = { hasError: false };
156	
157	      // if field + value are valid, we should end with 2 items only
158	      if (fieldValue.length == 2) {
159	        const searchValue = fieldValue[0].toLowerCase();
160	        const def = filterDefinitions.find(def => def.id.toLowerCase() === searchValue);
161	        if (def) {
162	          // set compare
163	          if (v.includes(FilterCompare.moreThanOrEqual)) {
164	            if (def.component != 'number') {
165	              setMessage(
166	                t(
167	                  'More than operator is not allowed with `{{searchValue}}`. Use equals or contains operators instead.',
168	                  { searchValue }
169	                )
170	              );
171	              setIndicator(ValidatedOptions.error);
172	              return { ...result, hasError: true };
173	            }
174	            setCompare(FilterCompare.moreThanOrEqual);
175	            result.comparator = FilterCompare.moreThanOrEqual;
176	          } else if (v.includes(FilterCompare.notEqual)) {
177	            setCompare(FilterCompare.notEqual);
178	            result.comparator = FilterCompare.notEqual;
179	          } else if (v.includes(FilterCompare.equal)) {
180	            setCompare(FilterCompare.equal);
181	            result.comparator = FilterCompare.equal;
182	          } else {
183	            if (def.component === 'number') {
184	              setMessage(
185	                t(
186	                  'Contains operator is not allowed with `{{searchValue}}`. Use equals or more than operators instead.',
187	                  { searchValue }
188	                )
189	              );
190	              setIndicator(ValidatedOptions.error);
191	              return { ...result, hasError: true };
192	            } else if (v.includes(FilterCompare.notMatch)) {
193	              setCompare(FilterCompare.notMatch);
194	              result.comparator = FilterCompare.notMatch;
195	            } else {
196	              setCompare(FilterCompare.match);
197	              result.comparator = FilterCompare.match;
198	            }
199	          }
200	          // set direction
201	          if (def.category === 'source') {
202	            setDirection('source');
203	          } else if (def.category === 'destination') {
204	            setDirection('destination');
205	          } else {
206	            setDirection(undefined);
207	          }
208	          //set filter
209	          setFilter(def);
210	          result.def = def;
211	        } else if (submitOnRefresh) {
212	          setMessage(t("Can't find filter `{{searchValue}}`", { searchValue }));
213	          setIndicator(ValidatedOptions.error);
214	          return { ...result, hasError: true };
215	        }
216	        setValue(fieldValue[1]);
217	        result.value = fieldValue[1];
218	      } else if (fieldValue.length === 1) {
219	        // check if the value match a field
220	        const searchValue = v.toLowerCase();
221	        const def = filterDefinitions.find(def => def.id.toLowerCase() === searchValue);
222	        if (def) {
223	          // set direction
224	          if (def.category === 'source') {
225	            setDirection('source');
226	          } else if (def.category === 'destination') {
227	            setDirection('destination');
228	          } else {
229	            setDirection(undefined);
230	          }
231	          // set filter and reset the rest
232	          setFilter(def);
233	          setCompare(FilterCompare.match);
234	          setValue('');
235	          result.def = def;
236	        } else {
237	          // set simple value on current filter
238	          setValue(v);
239	          result.value = v;
240	        }
241	      } else {
242	        setMessage(t('Invalid format. The input should be <filter><comparator><value> such as `name=netobserv`.'));
243	        setIndicator(ValidatedOptions.error);
244	        return { ...result, hasError: true };
245	      }
246	
247	      if (submitOnRefresh) {
248	        setSubmitPending(true);
249	      }
250	
251	      return result;
252	    },
253	    // eslint-disable-next-line react-hooks/exhaustive-deps
254	    [compare, filterDefinitions, searchInputValue, setMessage]
255	  );
256	
257	  const getEncodedValue = React.useCallback(
258	    (v: string = value) => {
259	      return matcher(filter.id, [v], compare);
260	    },
261	    [compare, filter, value]
262	  );
263	
264	  const onToggle = React.useCallback(() => {
265	    setSuggestions([]);
266	    if (!isPopperOpen) {
267	      updateForm();
268	      setPopperOpen(true);
269	    }
270	  }, [isPopperOpen, updateForm]);
271	
272	  const onSearchChange = React.useCallback(
273	    (v: string) => {
274	      const defToSuggestion = (fd: FilterDefinition) => {
275	        return {
276	          display:
277	            fd.category === 'source'
278	              ? `${t('Source')} ${fd.name}`
279	              : fd.category === 'destination'
280	              ? `${t('Destination')} ${fd.name}`
281	              : fd.name,
282	          value: fd.id,
283	          validate: false,
284	          filterDef: fd
285	        };
286	      };
287	
288	      const optionToSuggestion = (o: FilterOption) => {
